const raw = $input.first().json.result || '';
const match = raw.match(/\{[\s\S]*\}/);
let parsed = {};
try { parsed = JSON.parse(match ? match[0] : raw); } catch (e) { parsed = { draft: raw, parse_error: e.message }; }
parsed.brief = $('Webhook (topic + channel)').first().json.body.brief;
parsed.channel = $('Webhook (topic + channel)').first().json.body.channel || 'linkedin_post';
parsed.created_at = new Date().toISOString();
return { json: parsed };

